import React, { useState } from 'react';
import { Link, useNavigate, useLocation } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { useTheme } from '../context/ThemeContext';
import ThemeToggle from './ThemeToggle';
import {
  Cpu, LayoutDashboard, TrendingUp, LogOut,
  ShieldCheck, Terminal, User, Menu, X,
  Globe, Archive
} from 'lucide-react';

const Navbar = () => {
  const { user, logout }           = useAuth();
  const navigate                   = useNavigate();
  const location                   = useLocation();
  const [mobileOpen, setMobileOpen] = useState(false);

  /* Consume theme so re-renders fire on toggle */
  const { isDarkMode } = useTheme(); 

  const handleLogout = () => {
    logout();
    setMobileOpen(false);
    navigate('/login');
  };

  const isActive = (path) => location.pathname === path;

  const linkStyle = (active, accent = false) => ({
    textDecoration: 'none',
    fontWeight: 700,
    fontSize: '9px', // Slightly smaller for more items
    padding: '0.45rem 0.8rem',
    borderRadius: '10px',
    display: 'flex',
    alignItems: 'center',
    gap: '6px',
    textTransform: 'uppercase',
    letterSpacing: '0.1em',
    whiteSpace: 'nowrap',
    transition: 'all 0.25s ease',
    cursor: 'pointer',
    ...(accent ? {
      backgroundImage: 'linear-gradient(135deg, var(--accent-secondary), var(--accent-primary))',
      color: '#ffffff',
      border: 'none',
      boxShadow: '0 0 12px var(--accent-glow)',
    } : active ? {
      backgroundColor: 'var(--accent-muted)',
      color: 'var(--accent-primary)',
      border: '1px solid var(--accent-primary)',
    } : {
      backgroundColor: 'transparent',
      color: 'var(--text-secondary)',
      border: '1px solid transparent',
    }),
  });

  const navLinks = user ? (
    <>
      <Link to="/dashboard" style={linkStyle(isActive('/dashboard'))} onClick={() => setMobileOpen(false)}>
        <LayoutDashboard size={12} /> Dashboard
      </Link>
      <Link to="/generate" style={linkStyle(isActive('/generate'))} onClick={() => setMobileOpen(false)}>
        <TrendingUp size={12} /> Strategy
      </Link>
      {/* 📡 NEW: Live Market Node */}
      <Link to="/live" style={linkStyle(isActive('/live'))} onClick={() => setMobileOpen(false)}>
        <Globe size={12} /> Live_Pulse
      </Link>
      {/* 🏛️ NEW: Strategy Vault Node */}
      <Link to="/vault" style={linkStyle(isActive('/vault'))} onClick={() => setMobileOpen(false)}>
        <Archive size={12} /> Vault
      </Link>
      <Link to="/profile" style={linkStyle(isActive('/profile'))} onClick={() => setMobileOpen(false)}>
        <User size={12} /> Node
      </Link>
      <button
        onClick={handleLogout}
        style={{
          backgroundColor: 'rgba(239,68,68,0.06)',
          color: '#ef4444',
          border: '1px solid rgba(239,68,68,0.15)',
          padding: '0.45rem 0.75rem',
          borderRadius: '10px',
          cursor: 'pointer',
          display: 'flex',
          alignItems: 'center',
          gap: '6px',
          fontSize: '9px',
          fontWeight: 700,
          textTransform: 'uppercase',
          letterSpacing: '0.1em',
          transition: 'all 0.25s ease',
        }}
      >
        <LogOut size={12} /> Logout
      </button>
    </>
  ) : (
    <>
      <Link to="/login" style={linkStyle(isActive('/login'))} onClick={() => setMobileOpen(false)}>
        <Terminal size={12} /> Access
      </Link>
      <Link to="/register" style={linkStyle(false, true)} onClick={() => setMobileOpen(false)}>
        <ShieldCheck size={12} /> Initialize
      </Link>
    </>
  );

  return (
    <>
      <div style={{
        position: 'sticky',
        top: 0,
        zIndex: 200,
        width: '100%',
        padding: '12px 16px',
        boxSizing: 'border-box',
        backgroundColor: 'var(--bg-main)',
        pointerEvents: 'none',
      }}>
        <nav style={{
          pointerEvents: 'auto',
          width: '100%',
          maxWidth: '1200px', // Widened to accommodate new links
          margin: '0 auto',
          backgroundColor: 'var(--surface-glass)',
          backdropFilter: 'blur(20px)',
          WebkitBackdropFilter: 'blur(20px)',
          border: '1px solid var(--surface-border)',
          borderRadius: '18px',
          boxShadow: 'var(--shadow-elevated)',
          padding: '0.5rem 1rem',
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'space-between',
        }}>
          {/* Brand */}
          <Link to="/" style={{
            textDecoration: 'none',
            display: 'flex',
            alignItems: 'center',
            gap: '10px',
            color: 'var(--text-primary)',
            fontWeight: 800,
            fontSize: '0.8rem',
            letterSpacing: '0.15em',
            textTransform: 'uppercase',
            flexShrink: 0,
          }}>
            <div style={{
              width: '32px', height: '32px', borderRadius: '10px',
              background: 'var(--accent-muted)',
              border: '1px solid var(--accent-primary)',
              display: 'flex', alignItems: 'center', justifyContent: 'center',
              boxShadow: '0 0 10px var(--accent-glow)',
            }}>
              <Cpu size={14} color="var(--accent-primary)" />
            </div>
            Finify AI
          </Link>

          {/* Desktop links */}
          <div className="finify-desktop-nav" style={{ display: 'flex', alignItems: 'center', gap: '0.25rem' }}>
            {navLinks}
            <div style={{ marginLeft: '0.5rem', paddingLeft: '0.5rem', borderLeft: '1px solid var(--surface-border)' }}>
               <ThemeToggle />
            </div>
          </div>

          {/* Hamburger */}
          <button
            onClick={() => setMobileOpen(v => !v)}
            className="finify-hamburger"
            style={{
              display: 'none',
              background: 'none',
              border: '1px solid var(--surface-border)',
              borderRadius: '8px',
              padding: '0.4rem',
              color: 'var(--text-primary)',
            }}
          >
            {mobileOpen ? <X size={18} /> : <Menu size={18} />}
          </button>
        </nav>

        {/* Mobile dropdown */}
        {mobileOpen && (
          <div style={{
            pointerEvents: 'auto',
            width: '100%',
            maxWidth: '1200px',
            margin: '6px auto 0',
            backgroundColor: 'var(--surface-glass)',
            backdropFilter: 'blur(20px)',
            border: '1px solid var(--surface-border)',
            borderRadius: '14px',
            padding: '0.75rem',
            display: 'flex',
            flexDirection: 'column',
            gap: '0.35rem',
          }}>
            {navLinks}
            <div style={{ borderTop: '1px solid var(--surface-border)', marginTop: '0.5rem', paddingTop: '0.5rem' }}>
                <ThemeToggle />
            </div>
          </div>
        )}
      </div>

      <style>{`
        @media (max-width: 900px) {
          .finify-desktop-nav { display: none !important; }
          .finify-hamburger    { display: flex !important; }
        }
      `}</style>
    </>
  );
};

export default Navbar;
